+fn parse_listpack_integer(entry: &[u8]) -> Option<i64> {
+    if entry.is_empty() || entry.len() >= 21 {
+        return None;
+    }
+    let value = std::str::from_utf8(entry).ok()?.parse::<i64>().ok()?;
+    if value.to_string().as_bytes() == entry {
+        Some(value)
+    } else {
+        None
+    }
+}
